   282→// hasWebSearch checks whether the request contains a GoogleSearch tool marker,
   283→// indicating the caller wants web search capability.
   284→func hasWebSearch(req *model.LLMRequest) bool {
   285→	if req.Config == nil {
   286→		return false
   287→	}
   288→	for _, t := range req.Config.Tools {
   289→		if t != nil && t.GoogleSearch != nil {
   290→			return true
   291→		}
   292→	}
   293→	return false
   294→}
