   296→// convertTools transforms ADK genai.Tool definitions into OpenAI tool format.
   297→func convertTools(req *model.LLMRequest) []chatTool {
   298→	if req.Config == nil || len(req.Config.Tools) == 0 {
   299→		return nil
   300→	}
   301→
   302→	var tools []chatTool
   303→	for _, t := range req.Config.Tools {
   304→		if t.GoogleSearch != nil {
   305→			continue
   306→		}
   307→		for _, fd := range t.FunctionDeclarations {
   308→			ct := chatTool{
   309→				Type: "function",
   310→				Function: chatFunction{
   311→					Name:        fd.Name,
   312→					Description: fd.Description,
   313→				},
   314→			}
   315→			if fd.Parameters != nil {
   316→				ct.Function.Parameters = schemaToMap(fd.Parameters)
   317→			}
   318→			tools = append(tools, ct)
   319→		}
   320→	}
   321→	return tools
   322→}
